import math


def check_currency_unit_consistency(record, ref):
    price = ref.PRICE_FEED.get((record.ticker, record.as_of_date))
    if price is None or record.shares <= 0:
        return Verdict(
            outcome="true",
            confidence=1.0,
            reason="not applicable: no independent price is available for this row.",
            evidence={"applicable": False},
            check_name="check_currency_unit_consistency",
        )
    est = record.shares * price
    if est <= 0:
        return Verdict(
            outcome="true",
            confidence=1.0,
            reason="not applicable: the independent estimate is zero.",
            evidence={"applicable": False},
            check_name="check_currency_unit_consistency",
        )
    ratio = record.value_usd / est
    for currency, fx_rate in ref.FX.items():
        if math.isclose(ratio, fx_rate, rel_tol=0.02):
            label = "won-to-dollar" if currency == "KRW" else currency + "-to-dollar"
            return Verdict(
                outcome="held",
                confidence=1.0,
                reason="WRONG UNITS: this value is in " + currency + ", not dollars (" + format(fx_rate, ",.0f") + "x = the " + label + " rate).",
                evidence={"tag": "WRONG UNITS", "currency": currency, "ratio": ratio, "fx_rate": fx_rate},
                check_name="check_currency_unit_consistency",
            )
    return Verdict(
        outcome="true",
        confidence=1.0,
        reason="currency-unit check passed: the value is not close to a known FX multiple.",
        evidence={"ratio": ratio},
        check_name="check_currency_unit_consistency",
    )
